154	  async doGenerate({
155	    prompt,
156	    files,
157	    mask,
158	    size,
159	    aspectRatio,
160	    seed,
161	    providerOptions,
162	    headers,
163	    abortSignal,
164	  }: Parameters<ImageModelV3['doGenerate']>[0]): Promise<
