221	
222	    const { value: imageBytes, responseHeaders } = await getFromApi({
223	      url: imageUrl,
224	      headers: combinedHeaders,
225	      abortSignal,
226	      failedResponseHandler: createStatusCodeErrorResponseHandler(),
