381	function convertSizeToAspectRatio(
382	  size: string,
383	): BlackForestLabsAspectRatio | undefined {
384	  const [wStr, hStr] = size.split('x');
385	  const width = Number(wStr);
386	  const height = Number(hStr);
387	  if (
388	    !Number.isFinite(width) ||
389	    !Number.isFinite(height) ||
390	    width <= 0 ||
391	    height <= 0
392	  ) {
393	    return undefined;
394	  }
395	  const g = gcd(width, height);
396	  return `${Math.round(width / g)}:${Math.round(height / g)}`;
397	}
398	
399	function gcd(a: number, b: number): number {
400	  let x = Math.abs(a);
401	  let y = Math.abs(b);
402	  while (y !== 0) {
403	    const t = y;
404	    y = x % y;
405	    x = t;
406	  }
407	  return x;
408	}
