91	interface FireworksImageModelConfig {
92	  provider: string;
93	  baseURL: string;
94	  headers: () => Record<string, string>;
95	  fetch?: FetchFunction;
96	  /**
97	   * Poll interval in milliseconds between status checks for async models.
98	   * Defaults to 500ms.
99	   */
100	  pollIntervalMillis?: number;
101	  /**
102	   * Overall timeout in milliseconds for polling before giving up.
103	   * Defaults to 120000ms (2 minutes).
104	   */
105	  pollTimeoutMillis?: number;
106	  _internal?: {
107	    currentDate?: () => Date;
108	  };
109	}
