  | 'pixelart-standard'
  | 'pixelart-hd'
  | (string & {});
```

No additional types needed here (BFL exports `BlackForestLabsAspectRatio` because it converts size to aspect ratio; PixelArt natively supports `size`, so no such helper type is needed).

---

#### File 10: `packages/pixelart/src/pixelart-image-model.ts`

This is the core file. It implements `ImageModelV3` with a single synchronous POST returning base64 JSON. Key design points:

- **URL structure**: `POST {baseURL}/generate/{modelId}` -- a clean fictional API design.
- **Request body**: `{ prompt, size, seed, n, style, pixel_density }`. The `style` and `pixel_density` come from provider options; `prompt`, `size`, `seed`, `n` come from core call options.
- **Response body**: `{ images: [{ b64_json: string }], model: string }` -- a simple base64 JSON format.
- **Unsupported features**: `aspectRatio` (PixelArt uses `size` directly), `files` (no editing), `mask` (no inpainting) all produce warnings.
- **Provider metadata**: Returns `pixelArt.images` array (matching the convention of `blackForestLabs.images`).

```ts
import type { ImageModelV3, SharedV3Warning } from '@ai-sdk/provider';
import type { InferSchema, Resolvable } from '@ai-sdk/provider-utils';
import {
  FetchFunction,
  combineHeaders,
  createJsonErrorResponseHandler,
  createJsonResponseHandler,
  lazySchema,
  parseProviderOptions,
  postJsonToApi,
  resolve,
  zodSchema,
} from '@ai-sdk/provider-utils';
import { z } from 'zod/v4';
import { PixelArtImageModelId } from './pixelart-image-settings';

// -- Config interface (matches BFL pattern) --
interface PixelArtImageModelConfig {
  provider: string;
  baseURL: string;
  headers?: Resolvable<Record<string, string | undefined>>;
  fetch?: FetchFunction;
  _internal?: {
    currentDate?: () => Date;
  };
}

// -- The model class --
export class PixelArtImageModel implements ImageModelV3 {
  readonly specificationVersion = 'v3';
  readonly maxImagesPerCall = 4;

  get provider(): string {
    return this.config.provider;
  }

  constructor(
    readonly modelId: PixelArtImageModelId,
    private readonly config: PixelArtImageModelConfig,
  ) {}

  async doGenerate({
    prompt,
    n,
    size,
    aspectRatio,
    seed,
    providerOptions,
    headers,
    abortSignal,
    files,
    mask,
  }: Parameters<ImageModelV3['doGenerate']>[0]): Promise<
    Awaited<ReturnType<ImageModelV3['doGenerate']>>
  > {
    const warnings: Array<SharedV3Warning> = [];

    // PixelArt does not support aspectRatio -- it uses size directly
    if (aspectRatio != null) {
      warnings.push({
        type: 'unsupported',
        feature: 'aspectRatio',
        details:
          'PixelArt does not support aspectRatio. Use size instead.',
      });
    }

    // No image editing support
    if (files != null && files.length > 0) {
      warnings.push({
        type: 'unsupported',
        feature: 'files',
        details: 'PixelArt does not support image editing.',
      });
    }

    if (mask != null) {
      warnings.push({
        type: 'unsupported',
        feature: 'mask',
        details: 'PixelArt does not support inpainting masks.',
      });
    }

    // Parse provider-specific options
    const pixelArtOptions = await parseProviderOptions({
      provider: 'pixelArt',
      providerOptions,
      schema: pixelArtImageModelOptionsSchema,
    });

    const currentDate = this.config._internal?.currentDate?.() ?? new Date();
    const combinedHeaders = combineHeaders(
      await resolve(this.config.headers),
      headers,
    );

    const body: Record<string, unknown> = {
      prompt,
      ...(size != null && { size }),
      ...(seed != null && { seed }),
      n,
      ...(pixelArtOptions?.style != null && { style: pixelArtOptions.style }),
      ...(pixelArtOptions?.pixelDensity != null && {
        pixel_density: pixelArtOptions.pixelDensity,
      }),
    };

    const { value: response, responseHeaders } = await postJsonToApi({
      url: `${this.config.baseURL}/generate/${this.modelId}`,
      headers: combinedHeaders,
      body,
      failedResponseHandler: pixelArtFailedResponseHandler,
      successfulResponseHandler: createJsonResponseHandler(
        pixelArtResponseSchema,
      ),
      abortSignal,
      fetch: this.config.fetch,
    });

    return {
      images: response.images.map(image => image.b64_json),
      warnings,
      providerMetadata: {
        pixelArt: {
          images: response.images.map(() => ({})),
        },
      },
      response: {
        timestamp: currentDate,
        modelId: this.modelId,
        headers: responseHeaders,
      },
    };
  }
}

// -- Provider options schema (style + pixelDensity) --
export const pixelArtImageModelOptionsSchema = lazySchema(() =>
  zodSchema(
    z.object({
      style: z.enum(['pixel', 'retro', '8bit']).optional(),
      pixelDensity: z.number().int().min(1).max(4).optional(),
    }),
  ),
);

export type PixelArtImageModelOptions = InferSchema<
  typeof pixelArtImageModelOptionsSchema
>;

// -- Response schema --
const pixelArtResponseSchema = z.object({
  images: z.array(
    z.object({
      b64_json: z.string(),
    }),
  ),
  model: z.string().optional(),
});

// -- Error handling --
const pixelArtErrorSchema = z.object({
  error: z
    .object({
      message: z.string(),
      code: z.string().optional(),
    })
    .optional(),
});

const pixelArtFailedResponseHandler = createJsonErrorResponseHandler({
  errorSchema: pixelArtErrorSchema,
  errorToMessage: error => error.error?.message ?? 'Unknown PixelArt error',
});
```

Key patterns preserved from BFL:
- `Resolvable<Record<string, string | undefined>>` for headers in config
- `combineHeaders(await resolve(this.config.headers), headers)` for merging provider + request headers
- `_internal.currentDate` for testability
- `lazySchema(zodSchema(...))` for the provider options schema
- `InferSchema<typeof schema>` for the exported type
