import { FetchFunction } from '@ai-sdk/provider-utils';
import { createTestServer } from '@ai-sdk/test-server/with-vitest';
import { describe, expect, it } from 'vitest';
import { PixelArtImageModel } from './pixelart-image-model';

const prompt = 'A cute pixel art cat';

function createBasicModel({
  headers,
  fetch,
  currentDate,
}: {
  headers?: () => Record<string, string | undefined>;
  fetch?: FetchFunction;
  currentDate?: () => Date;
} = {}) {
  return new PixelArtImageModel('pixelart-standard', {
    provider: 'pixelart.image',
    baseURL: 'https://api.example.com/v1',
    headers: headers ?? (() => ({ Authorization: 'Bearer test-key' })),
    fetch,
    _internal: {
      currentDate,
    },
  });
}

const defaultResponse = {
  images: [{ b64_json: 'dGVzdC1pbWFnZS1kYXRh' }],
  model: 'pixelart-standard',
};

describe('PixelArtImageModel', () => {
  const server = createTestServer({
    'https://api.example.com/v1/generate/pixelart-standard': {
      response: {
        type: 'json-value',
        body: defaultResponse,
      },
    },
  });

  describe('constructor', () => {
    it('should have correct provider', () => {
      const model = createBasicModel();
      expect(model.provider).toBe('pixelart.image');
    });

    it('should have correct modelId', () => {
      const model = createBasicModel();
      expect(model.modelId).toBe('pixelart-standard');
    });

    it('should have correct specificationVersion', () => {
      const model = createBasicModel();
      expect(model.specificationVersion).toBe('v3');
    });

    it('should have correct maxImagesPerCall', () => {
      const model = createBasicModel();
      expect(model.maxImagesPerCall).toBe(4);
    });
  });

  describe('doGenerate', () => {
    it('passes prompt and n in the request body', async () => {
      const model = createBasicModel();

      await model.doGenerate({
        prompt,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
        files: undefined,
        mask: undefined,
      });

      expect(await server.calls[0].requestBodyJson).toStrictEqual({
        prompt,
        n: 1,
      });
    });

    it('passes size and seed in the request body', async () => {
      const model = createBasicModel();

      await model.doGenerate({
        prompt,
        n: 2,
        size: '512x512',
        aspectRatio: undefined,
        seed: 42,
        providerOptions: {},
        files: undefined,
        mask: undefined,
      });

      expect(await server.calls[0].requestBodyJson).toStrictEqual({
        prompt,
        n: 2,
        size: '512x512',
        seed: 42,
      });
    });

    it('passes provider options style and pixelDensity', async () => {
      const model = createBasicModel();

      await model.doGenerate({
        prompt,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {
          pixelArt: {
            style: 'retro',
            pixelDensity: 3,
          },
        },
        files: undefined,
        mask: undefined,
      });

      expect(await server.calls[0].requestBodyJson).toStrictEqual({
        prompt,
        n: 1,
        style: 'retro',
        pixel_density: 3,
      });
    });

    it('ignores unknown provider options', async () => {
      const model = createBasicModel();

      await model.doGenerate({
        prompt,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {
          pixelArt: {
            style: '8bit',
            unknownProperty: 'ignored',
          },
        },
        files: undefined,
        mask: undefined,
      });

      expect(await server.calls[0].requestBodyJson).toStrictEqual({
        prompt,
        n: 1,
        style: '8bit',
      });
    });

    it('returns base64 images from the response', async () => {
      server.urls[
        'https://api.example.com/v1/generate/pixelart-standard'
      ].response = {
        type: 'json-value',
        body: {
          images: [
            { b64_json: 'aW1hZ2UxZGF0YQ==' },
            { b64_json: 'aW1hZ2UyZGF0YQ==' },
          ],
          model: 'pixelart-standard',
        },
      };

      const model = createBasicModel();

      const result = await model.doGenerate({
        prompt,
        n: 2,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
        files: undefined,
        mask: undefined,
      });

      expect(result.images).toStrictEqual([
        'aW1hZ2UxZGF0YQ==',
        'aW1hZ2UyZGF0YQ==',
      ]);
    });

    it('produces a warning for unsupported aspectRatio', async () => {
      const model = createBasicModel();

      const result = await model.doGenerate({
        prompt,
        n: 1,
        size: undefined,
        aspectRatio: '16:9',
        seed: undefined,
        providerOptions: {},
        files: undefined,
        mask: undefined,
      });

      expect(result.warnings).toStrictEqual([
        {
          type: 'unsupported',
          feature: 'aspectRatio',
          details: 'PixelArt does not support aspectRatio. Use size instead.',
        },
      ]);
    });

    it('produces a warning for unsupported files', async () => {
      const model = createBasicModel();

      const result = await model.doGenerate({
        prompt,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
        files: [
          {
            type: 'file',
            data: 'dGVzdA==',
            mediaType: 'image/png',
          },
        ],
        mask: undefined,
      });

      expect(result.warnings).toStrictEqual([
        {
          type: 'unsupported',
          feature: 'files',
          details: 'PixelArt does not support image editing.',
        },
      ]);
    });

    it('produces a warning for unsupported mask', async () => {
      const model = createBasicModel();

      const result = await model.doGenerate({
        prompt,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
        files: undefined,
        mask: {
          type: 'base64',
          data: 'dGVzdA==',
          mediaType: 'image/png',
        },
      });

      expect(result.warnings).toStrictEqual([
        {
          type: 'unsupported',
          feature: 'mask',
          details: 'PixelArt does not support inpainting masks.',
        },
      ]);
    });

    it('sends the correct URL', async () => {
      const model = createBasicModel();

      await model.doGenerate({
        prompt,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
        files: undefined,
        mask: undefined,
      });

      expect(server.calls[0].requestUrl).toBe(
        'https://api.example.com/v1/generate/pixelart-standard',
      );
      expect(server.calls[0].requestMethod).toBe('POST');
    });

    it('sends provider headers', async () => {
      const model = createBasicModel({
        headers: () => ({
          Authorization: 'Bearer my-key',
          'x-custom': 'custom-value',
        }),
      });

      await model.doGenerate({
        prompt,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
        files: undefined,
        mask: undefined,
      });

      expect(server.calls[0].requestHeaders['authorization']).toBe(
        'Bearer my-key',
      );
      expect(server.calls[0].requestHeaders['x-custom']).toBe('custom-value');
    });

    it('merges request headers with provider headers', async () => {
      const model = createBasicModel({
        headers: () => ({
          Authorization: 'Bearer my-key',
        }),
      });

      await model.doGenerate({
        prompt,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
        files: undefined,
        mask: undefined,
        headers: {
          'x-request-header': 'request-value',
        },
      });

      expect(server.calls[0].requestHeaders['authorization']).toBe(
        'Bearer my-key',
      );
      expect(server.calls[0].requestHeaders['x-request-header']).toBe(
        'request-value',
      );
    });

    it('returns response metadata', async () => {
      const testDate = new Date('2024-01-01T00:00:00Z');
      const model = createBasicModel({
        currentDate: () => testDate,
      });

      server.urls[
        'https://api.example.com/v1/generate/pixelart-standard'
      ].response = {
        type: 'json-value',
        headers: {
          'x-request-id': 'req-123',
        },
        body: defaultResponse,
      };

      const result = await model.doGenerate({
        prompt,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
        files: undefined,
        mask: undefined,
      });

      expect(result.response.timestamp).toStrictEqual(testDate);
      expect(result.response.modelId).toBe('pixelart-standard');
      expect(result.response.headers?.['x-request-id']).toBe('req-123');
    });

    it('returns provider metadata', async () => {
      const model = createBasicModel();

      const result = await model.doGenerate({
        prompt,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
        files: undefined,
        mask: undefined,
      });

      expect(result.providerMetadata).toStrictEqual({
        pixelArt: {
          images: [{}],
        },
      });
    });
  });
});
